import './App.css';
import React, {useState, useEffect} from "react";
import logo from './logo.jpg';
import firebase from "./firebase.js";
import "firebase/firestore";
import { v4 as uuidv4 } from 'uuid';

function App() {
  const [songs, setSongs] = useState([]);
  const [name, setName] = useState([]);
  const [songTitle, setSongTitle] = useState([]);
  const [artist, setArtist] = useState([]);
  const [notes, setNotes] = useState([]);
  const [id, setId] = useState([]);

  const ref = firebase.firestore().collection("songs");
  function getSongs() {
    ref.onSnapshot((querySnapshot) => {
      const items = [];
      querySnapshot.forEach((doc) => {
        items.push(doc.data())
      })
      setSongs(items)
      console.log(songs)
    })

  }
  console.log(songs)
  useEffect( () => {
    getSongs();
  }, [])
 

  function addSong(newSong) {
    ref.doc(newSong.id)
    .set(newSong)
    .catch((err) => {
      console.error(err)
    })
  }

  function deleteSong(song) {
    ref.doc(song.id)
    .delete()
    .catch((err) => {
      console.error(err)
    })
  }

  return (
    <div className="App">
        <h1> Welcome To Mr.Goodbar Karaoke</h1>
        <img src={logo} alt="Logo" />
        <h2>Presented by Miah and Mucks</h2> 
        <h2>Please Enter Your Request</h2> 
        <h4>Book Your Own Private Goodbar Karaoke Party!</h4> 
      <div className="info">
        <form>
          <label>
          Your Name:
          <input type="text" name="name" onChange={(e) => setName(e.target.value)}/>  
          </label> <br></br>
          <label><br></br>
          Artist/band:
            <input type="text" name="name" onChange={(e) => setArtist(e.target.value)} />
          </label><br></br>
          <label><br></br>
          Song Title:
            <input type="text" name="name" onChange={(e) => setSongTitle(e.target.value)} />
          </label><br></br>
     
          <label><br></br>
          Additional Notes:
            <textarea type="text" name="name" onChange={(e) => setNotes(e.target.value)}/>
          </label><br></br>
          <br></br>
          <button onClick={() => addSong( {name, songTitle, artist, notes, id: uuidv4() })} >
          Submit
         </button>
        </form>
          
        {songs.map((song) => (
        <div className="songcard" key={song.name}>
          <span onClick={(e) => deleteSong(song)} style={{color:'red'}}>x</span>
          <h2>Singer Name: {song.name}</h2>
          <h2>Artist: {song.artist}</h2>
          <h2>Song:{song.songTitle}</h2>
          </div>
      ))}
      </div>   
    </div>
  );
}

export default App;
